import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_travel_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(cur_truck_pos - customer_pos)

        for j, truck_pos in enumerate(all_truck_pos):
            if j != i:
                distance_to_depot = np.linalg.norm(customer_pos - depot_pos)
                total_distance = distance_to_customer + np.linalg.norm(customer_pos - truck_pos) + distance_to_depot
                travel_time = total_distance / truck_speed

                if current_time + travel_time <= time_windows[i][1]:
                    if travel_time < min_travel_time:
                        min_travel_time = travel_time
                        best_node = i

    return best_node
